1	import { Router } from "express";
2	import { orders, products, getNextOrderId } from "../data.js";
3	import type { CreateOrderInput, OrderItem } from "../types.js";
4	
5	const router = Router();
6	
7	// GET /orders - list orders, optionally filter by userId or status
8	router.get("/orders", (req, res) => {
9	  const { userId, status } = req.query;
10	
11	  let filtered = [...orders];
12	
13	  if (userId && typeof userId === "string") {
14	    const uid = parseInt(userId, 10);
15	    if (!isNaN(uid)) {
16	      filtered = filtered.filter((o) => o.userId === uid);
17	    }
18	  }
19	
20	  if (status && typeof status === "string") {
21	    filtered = filtered.filter((o) => o.status === status);
22	  }
23	
24	  // Calculate summary
25	  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);
26	
27	  res.json({
28	    orders: filtered,
29	    summary: {
30	      count: filtered.length,
31	      totalRevenue: Math.round(totalRevenue * 100) / 100,
32	    },
33	  });
34	});
35	
36	// GET /orders/:id
37	router.get("/orders/:id", (req, res) => {
38	  const id = parseInt(req.params.id, 10);
39	  const order = orders.find((o) => o.id === id);
40	
41	  if (!order) {
42	    res.status(404).json({ error: "Order not found" });
43	    return;
44	  }
45	
46	  // Enrich order items with product names
47	  const enrichedItems = order.items.map((item) => {
48	    const product = products.find((p) => p.id === item.productId);
49	    return {
50	      ...item,
51	      productName: product?.name ?? "Unknown",
52	    };
53	  });
54	
55	  res.json({
56	    ...order,
57	    items: enrichedItems,
58	  });
59	});
60	
61	// POST /orders - create a new order
62	router.post("/orders", (req, res) => {
63	  const input = req.body as CreateOrderInput;
64	
65	  if (!input.userId || !input.items || !Array.isArray(input.items)) {
66	    res.status(400).json({ error: "userId and items are required" });
67	    return;
68	  }
69	
70	  if (input.items.length === 0) {
71	    res.status(400).json({ error: "Order must have at least one item" });
72	    return;
73	  }
74	
75	  // Validate items and calculate totals
76	  const orderItems: OrderItem[] = [];
77	  let total = 0;
78	
79	  for (const item of input.items) {
80	    const product = products.find((p) => p.id === item.productId);
81	    if (!product) {
82	      res.status(400).json({ error: `Product ${item.productId} not found` });
83	      return;
84	    }
85	
86	    if (item.quantity <= 0) {
87	      res.status(400).json({ error: "Quantity must be positive" });
88	      return;
89	    }
90	
91	    if (product.stock < item.quantity) {
92	      res
93	        .status(400)
94	        .json({ error: `Insufficient stock for ${product.name}` });
95	      return;
96	    }
97	
98	    // Deduct stock
99	    product.stock -= item.quantity;
100	
101	    const itemTotal = product.price * item.quantity;
102	    orderItems.push({
103	      productId: product.id,
104	      quantity: item.quantity,
105	      price: product.price,
106	    });
107	    total += itemTotal;
108	  }
109	
110	  const order = {
111	    id: getNextOrderId(),
112	    userId: input.userId,
113	    items: orderItems,
114	    total: Math.round(total * 100) / 100,
115	    status: "pending" as const,
116	    createdAt: new Date().toISOString(),
117	  };
118	
119	  orders.push(order);
120	
121	  res.status(201).json(order);
122	});
123	
124	// PATCH /orders/:id/status - update order status
125	router.patch("/orders/:id/status", (req, res) => {
126	  const id = parseInt(req.params.id, 10);
127	  const order = orders.find((o) => o.id === id);
128	
129	  if (!order) {
130	    res.status(404).json({ error: "Order not found" });
131	    return;
132	  }
133	
134	  const { status } = req.body as { status: string };
135	  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
136	
137	  if (!validStatuses.includes(status)) {
138	    res.status(400).json({ error: `Invalid status. Must be one of: ${validStatuses.join(", ")}` });
139	    return;
140	  }
141	
142	  // Validate status transitions
143	  const transitions: Record<string, string[]> = {
144	    pending: ["confirmed"],
145	    confirmed: ["shipped"],
146	    shipped: ["delivered"],
147	    delivered: [],
148	  };
149	
150	  if (!transitions[order.status]?.includes(status)) {
151	    res.status(400).json({
152	      error: `Cannot transition from ${order.status} to ${status}`,
153	    });
154	    return;
155	  }
156	
157	  order.status = status as typeof order.status;
158	
159	  res.json(order);
160	});
161	
162	export { router as orderRouter };
